import{_ as e,o as t,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G05: 營收模式與收費策略 - 產品經理 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/4967_十銓/20260428/G05_營收模式與收費策略.md","filePath":"審計報告庫/經營審計/4967_十銓/20260428/G05_營收模式與收費策略.md"}'),i={name:"審計報告庫/經營審計/4967_十銓/20260428/G05_營收模式與收費策略.md"};function o(n,a,s,h,_,d){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="g05-營收模式與收費策略-產品經理-審計報告" tabindex="-1">G05: 營收模式與收費策略 - 產品經理 審計報告 <a class="header-anchor" href="#g05-營收模式與收費策略-產品經理-審計報告" aria-label="Permalink to &quot;G05: 營收模式與收費策略 - 產品經理 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司如何賺錢？營收來源結構為何？定價策略與同業相比有何差異？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>十銓以「品牌通路+原廠採購利差」為核心營收模式。2025 全年營收 204.28 億，2026Q1 營收 90.45 億（+69% YoY）。營收結構正從 B2C 為主（&gt;70%）快速轉向 B2B（47.58%），漲價循環中毛利率從 ~13% 飆升至 38.68%。定價策略為「低價囤貨+品牌溢價」雙軌並行。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>2025 營收 204.28 億（歷史新高），EPS 13.06 元</li><li>2026Q1 營收 90.45 億（+69% YoY），淨利 22.94 億，EPS 27 元</li><li>營收結構：B2C 52.42%、B2B 47.58%（2026Q1）</li></ul></li><li><strong>診斷見解</strong>：十銓的營收模式高度依賴原廠報價——買得便宜、賣得跟漲，賺取中間利差。B2B 轉型有助於穩定出貨量與毛利率，但無法改變「原廠主導定价」的產業結構。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>營收結構</strong>：B2C（消費/電競 DIY）佔 52.42%，B2B（企業級/工控/OEM）佔 47.58%（2026Q1）。B2B 比重從 2024 年低雙位數快速拉升，反映 AI 伺服器與工控需求爆發。</p></li><li><p><strong>定價策略</strong>：十銓採「低價囤貨+品牌溢價」雙軌。在 DRAM/NAND 低價期大量採購（2025 年 CapEx 5 億擴產），漲價週期中以品牌溢價出貨。2026Q1 毛利率 38.68% 反映此策略的超額回報。但此模式具有順週期特性——跌價時庫存減損將壓縮獲利。</p></li><li><p><strong>通路模式</strong>：全球 300-500 家代理商，紫光數碼為中國區總代理。北美與 ASI 等大型代理商合作。電商+實體通路並行，品牌溢價在電競與創作者市場有 5-15% 的價格空間。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>「華爾街空頭視角 (Skepticism Mandate)」</strong>：十銓的高毛利率（38.68%）是週期性產物，非結構性優勢。當 DRAM/NAND 價格在 2026 下半年或 2027 年回落，毛利率將快速回歸 10-15%，營運將面臨「營收成長但獲利衰退」的尷尬局面。B2B 雖然穩定，但企業級客戶的議價能力更強，長期可能壓縮毛利空間。此外，紫光數碼作為中國區總代理，地緣政治風險可能影響供應鏈穩定度。更深層的風險是「營收模式單一化」——十銓過度依賴記憶體價格波動，缺乏多元化的獲利來源，一旦產業進入下行週期，現金流壓力將快速浮現。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>2026Q1 法說會：營收 90.45 億、B2B 佔比 47.58%、毛利率 38.68%</li><li>十銓 2025 年報：營收 204.28 億、CapEx 約 5 億</li><li>TrendForce：2026Q2 DRAM 合約價預估季增 58-63%</li></ul>',13)])])}const u=e(i,[["render",o]]);export{p as __pageData,u as default};
